class Solution:
    def isRobotBounded(self, instructions):
        x, y = 0, 0
        dx, dy = 0, 1
        positions = []
        for _ in range(4):
            for c in instructions:
                if c == 'G':
                    x += dx
                    y += dy
                elif c == 'L':
                    dx, dy = -dy, dx
                else:
                    dx, dy = dy, -dx
            positions.append((x, y))
        return positions[-1] == (0, 0)

