class Solution:
    def isRobotBounded(self, instructions):
        x, y = 0, 0
        dx, dy = 0, 1
        for c in instructions:
            if c == 'G':
                x += dx
                y += dy
            elif c == 'L':
                dx, dy = -dy, dx
            else:
                dx, dy = dy, -dx
        return (x == 0 and y == 0) or (dx, dy) != (0, 1)

