var isRobotBounded = function(instructions) {
    let x = 0, y = 0, dx = 0, dy = 1;
    for (const c of instructions) {
        if (c === 'G') { x += dx; y += dy; }
        else if (c === 'L') { const t = dx; dx = -dy; dy = t; }
        else { const t = dx; dx = dy; dy = -t; }
    }
    return (x === 0 && y === 0) || dx !== 0 || dy !== 1;
};
